/**
 * cn-division — 省市区三级 Cascader 数据（不带编码版）
 * CommonJS 入口，供外部 CJS 包复用同一份 cn-division 数据。
 */

const DATA = require('../dist/no-code/pca.json');

let cache = null;

function getCascaderData() {
  if (cache) {
    return cache;
  }

  cache = Object.entries(DATA).map(([province, cities]) => ({
    label: province,
    value: province,
    children: Object.entries(cities).map(([city, counties]) => ({
      label: city,
      value: city,
      children: counties.map((county) => ({ label: county, value: county })),
    })),
  }));

  return cache;
}

module.exports = {
  getCascaderData,
};
